import{_ as a,o as l,c as n,ag as e}from"./chunks/framework.DXGyWiRo.js";const D=JSON.parse('{"title":"Getting Started With LinkedQL","description":"","frontmatter":{},"headers":[],"relativePath":"docs.md","filePath":"docs.md"}'),t={name:"docs.md"};function o(p,s,r,c,i,d){return l(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="getting-started-with-linkedql" tabindex="-1">Getting Started With LinkedQL <a class="header-anchor" href="#getting-started-with-linkedql" aria-label="Permalink to &quot;Getting Started With LinkedQL&quot;">​</a></h1><p>This guide takes you from installation to your first query with LinkedQL.</p><p>If you are totally new here, you may want to begin with <a href="/overview">What is LinkedQL</a>. If you are here for the embeddable local runtime, jump to <a href="/flashql">FlashQL</a>.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>Install the package from npm:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">npm</span><span style="color:#C3E88D;"> install</span><span style="color:#C3E88D;"> @linked-db/linked-ql</span></span></code></pre></div><p>The package exports the client entry points.</p><p>Import and use the Client for your database. LinkedQL works the same across all clients.</p><table tabindex="0"><thead><tr><th style="text-align:left;"><strong>Client</strong></th><th style="text-align:left;"><strong>Import Path</strong></th><th style="text-align:left;"><strong>Guide</strong></th></tr></thead><tbody><tr><td style="text-align:left;"><code>PGClient</code></td><td style="text-align:left;"><code>@linked-db/linked-ql/postgres</code></td><td style="text-align:left;"><a href="/docs/setup#postgresql">PostgreSQL ↗</a></td></tr><tr><td style="text-align:left;"><code>MySQLClient</code></td><td style="text-align:left;"><code>@linked-db/linked-ql/mysql</code></td><td style="text-align:left;"><a href="/docs/setup#mysql">MySQL ↗</a></td></tr><tr><td style="text-align:left;"><code>MariaDBClient</code></td><td style="text-align:left;"><code>@linked-db/linked-ql/mariadb</code></td><td style="text-align:left;"><a href="/docs/setup#mariadb">MariaDB ↗</a></td></tr><tr><td style="text-align:left;"><code>FlashQL</code></td><td style="text-align:left;"><code>@linked-db/linked-ql/flashql</code></td><td style="text-align:left;"><a href="/docs/setup#flashql">FlashQL ↗</a></td></tr><tr><td style="text-align:left;"><code>EdgeClient</code></td><td style="text-align:left;"><code>@linked-db/linked-ql/edge</code></td><td style="text-align:left;"><a href="/docs/setup#edgeclient">Edge / Browser ↗</a></td></tr><tr><td style="text-align:left;"><code>EdgeWorker</code></td><td style="text-align:left;"><code>@linked-db/linked-ql/edge-worker</code></td><td style="text-align:left;"><a href="/docs/setup#edgeworker">Edge Worker ↗</a></td></tr></tbody></table><h2 id="your-first-query-direct-database-client" tabindex="-1">Your First Query: Direct Database Client <a class="header-anchor" href="#your-first-query-direct-database-client" aria-label="Permalink to &quot;Your First Query: Direct Database Client&quot;">​</a></h2><p>A good first look is with a regular database client.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> PGClient</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> PGClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  host</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">localhost</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  port</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 5432</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  user</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  password</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">password</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  database</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">myapp</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT 10 AS value</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// [{ value: 10 }]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">disconnect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h2 id="your-first-query-local-runtime-with-flashql" tabindex="-1">Your First Query: Local Runtime With FlashQL <a class="header-anchor" href="#your-first-query-local-runtime-with-flashql" aria-label="Permalink to &quot;Your First Query: Local Runtime With FlashQL&quot;">​</a></h2><p>LinkedQL ships with FlashQL, an embeddable SQL runtime that runs in-process.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> FlashQL</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/flashql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  CREATE TABLE public.users (</span></span>
<span class="line"><span style="color:#C3E88D;">    id INT PRIMARY KEY,</span></span>
<span class="line"><span style="color:#C3E88D;">    name TEXT</span></span>
<span class="line"><span style="color:#C3E88D;">  );</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C3E88D;">  INSERT INTO public.users (id, name)</span></span>
<span class="line"><span style="color:#C3E88D;">  VALUES (1, &#39;Ada&#39;), (2, &#39;Linus&#39;);</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id, name</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.users</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// [{ id: 1, name: &#39;Ada&#39; }, { id: 2, name: &#39;Linus&#39; }]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">disconnect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>FlashQL has the same top-level query surface as the mainstream clients.</p><h2 id="what-comes-next" tabindex="-1">What Comes Next <a class="header-anchor" href="#what-comes-next" aria-label="Permalink to &quot;What Comes Next&quot;">​</a></h2><p>While deliberately simple, the same interface above quickly opens into deeper grounds:</p><ul><li>live queries with <code>{ live: true }</code></li><li>iterator-based querying with <code>db.stream()</code></li><li>table-level changefeed subscriptions with <code>db.wal.subscribe()</code></li><li>language extensions like DeepRefs and JSON literals</li><li>FlashQL orchestration with fedration, materialization, and sync</li></ul><h2 id="where-to-go-next" tabindex="-1">Where to Go Next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to Go Next&quot;">​</a></h2><ul><li><a href="/docs/setup">Setup Guide</a> for detailed setup by runtime</li><li><a href="/docs/query-api">Query Interface</a> for the common method contract</li><li><a href="/capabilities">Capabilities Overview</a> for language and runtime extensions</li><li><a href="/flashql">FlashQL</a> for the local runtime and sync model</li></ul>`,21)])])}const F=a(t,[["render",o]]);export{D as __pageData,F as default};
